package kr.gampa.battlegrounds.survival; public final class BoostGauge {private double percent;public double add(double amount){if(amount<0)throw new IllegalArgumentException();return percent=Math.min(100,percent+amount);}public void elapseSeconds(double seconds){if(seconds<0)throw new IllegalArgumentException();percent=Math.max(0,percent-seconds/3d);}public double percent(){return percent;}public double healPerEightSeconds(){if(percent<=0)return 0;if(percent<=20)return 1;if(percent<=60)return 2;if(percent<=90)return 3;return 4;}public double speedBonus(){if(percent>90)return .0625;if(percent>=60)return .025;return 0;}}